def _ascii_table(headers: list[str], rows: list[list[str]]) -> str:
    """Строит простую ASCII-таблицу для VK."""
    all_rows = [headers] + rows
    col_widths = [max(len(str(row[i])) for row in all_rows) for i in range(len(headers))]
    sep = "+" + "+".join("-" * (w + 2) for w in col_widths) + "+"

    def fmt_row(row: list[str]) -> str:
        cells = " | ".join(str(row[i]).ljust(col_widths[i]) for i in range(len(headers)))
        return f"| {cells} |"

    lines = [sep, fmt_row(headers), sep]
    for row in rows:
        lines.append(fmt_row(row))
    lines.append(sep)
    return "\n".join(lines)


def _fix_coeff_signs(q: str) -> str:
    """
    Исправляет OCR-артефакты знаков коэффициентов k и b в заданиях 67–70.
    Паттерны вида:
        k b\n<0, <0   →   k < 0, b < 0
        >0, >0\nk\nb   →   k > 0, b > 0
    """
    # Вариант 1: «<0, <0\nk\nb» или «k b\n<0, <0»
    q = re.sub(
        r"([kk])\s*\n?\s*([bб])\s*\n?\s*([<>]=?\s*0)\s*[,;]\s*([<>]=?\s*0)",
        lambda m: f"{m.group(1)} {m.group(3)}, {m.group(2)} {m.group(4)}",
        q,
    )
    # Вариант 2 (числа после знака разорваны переносом)
    q = re.sub(r"(<|>)(=?)\s*0\s*,?\s*\n?\s*(<|>)(=?)\s*0", r"\g<1>\g<2>0, \g<3>\g<4>0", q)

    # Типичные OCR-фрагменты: «k b <0, <0» → «k < 0, b < 0»
    patterns = [
        (r"k\s+b\s+(<)0,\s+(<)0",  r"k \g<1>0, b \g<2>0"),
        (r"k\s+b\s+(>)0,\s+(>)0",  r"k \g<1>0, b \g<2>0"),
        (r"k\s+b\s+(<)0,\s+(>)0",  r"k \g<1>0, b \g<2>0"),
        (r"k\s+b\s+(>)0,\s+(<)0",  r"k \g<1>0, b \g<2>0"),
    ]
    for pat, repl in patterns:
        q = re.sub(pat, repl, q)

    # Строки вида «1)\nk b <0, <0\n\n2)\nk b >0, >0»
    q = re.sub(
        r"\)\s*\n\s*k\s*\n\s*b\s*\n?\s*",
        r") k = ?, b = ?   ",   # временная заглушка, уберём ниже
        q,
    )

    # Финальная нормализация «< 0» / «> 0» без лишних пробелов внутри
    q = re.sub(r"([<>])\s+0", r"\1 0", q)
    return q


def _parse_abcd_derivative_table(body: str) -> dict[str, str]:
    """
    Парсит таблицу вида:
        A\n1)  0,5\nB\n2)  –0,7\nC\n3)  4\nD\n4)  –3
    Возвращает {A: '1', B: '2', C: '3', D: '4'} — соответствие точки → номеру.
    Здесь A–D — имена точек, 1–4 — пронумерованные значения.
    """
    point_re = re.compile(r"(?m)^([ABCD])\s*$")
    value_re = re.compile(r"^([1-4])\)\s*(.*)")

    entries: list[tuple[str, str, int]] = []   # (label, value_or_num, pos)
    for m in point_re.finditer(body):
        entries.append(("point", m.group(1), m.start()))
    for m in re.finditer(r"(?m)^([1-4])\)\s*(.*)", body):
        entries.append(("num", m.group(1) + ":" + m.group(2).strip(), m.start()))

    entries.sort(key=lambda x: x[2])

    # Строим словарь {point_letter: description_text}
    points: dict[str, str] = {}
    nums: dict[str, str] = {}

    for kind, val, _ in entries:
        if kind == "point":
            points[val] = val
        else:
            num, text = val.split(":", 1)
            nums[num] = text.strip()

    return {"points": points, "nums": nums}


