def clean_question_text(q: str, task_id: int) -> str:
    """
    Приводит условие задания 7 ЕГЭ база к читаемому виду для VK-бота.
    """
    q = q.replace("\r", "\n")

    # ── 1. Убираем колонтитул Ширяевой ──────────────────────────────────────
    q = re.sub(
        r"\n*\s*Е\.\s*А\.\s*Ширяева\s+Задачник\s+ЕГЭбаз\s+2026\s*\(тренаж[её]р\)\s*\n*",
        "\n",
        q,
        flags=re.IGNORECASE,
    )

    # ── 2. Дефисные переносы слов ────────────────────────────────────────────
    replacements = {
        "авто-мобиля":   "автомобиля",
        "авто-мобиле":   "автомобиле",
        "сое-динены":    "соединены",
        "вертика-ли":    "вертикали",
        "зак-рытия":     "закрытия",
        "рабо-чие":      "рабочие",
        "рабо-чих":      "рабочих",
        "указыва-ются":  "указываются",
        "зави-симость":  "зависимость",
        "зави-симости":  "зависимости",
        "це-на":         "цена",
        "сое-динены":    "соединены",
        "авто-":         "авто",
        "H⋅м":           "Н⋅м",
        "Н\uf0d7м":      "Н⋅м",
        "о\n0,5%":       "от 0,5%",
    }
    for old, new in replacements.items():
        q = q.replace(old, new)

    # ── 3. Латинская «c» → русская «с» в единицах времени ───────────────────
    q = re.sub(r"(\d)\s*c\b", r"\1 с", q)
    q = re.sub(r"–(\d+)\s*c\b", r"–\1 с", q)

    # ── 4. Убираем строки старого ответа ────────────────────────────────────
    q = re.sub(r"\n*\s*Ответ:\s*[АA]\s*[БB]\s*[ВC]\s*[ГD]\s*\n?", "\n", q, flags=re.IGNORECASE)
    q = re.sub(r"\n*\s*Ответ:\s*A\s*B\s*C\s*D\s*\n?", "\n", q, flags=re.IGNORECASE)
    # [^.]* вместо .*? — не пересекаем границу предложения (точку),
    # иначе "В таблице показаны..." тоже удалится
    q = re.sub(r"\n+\s*В таблице [^.]*?(?:номер|производной)\.?\s*$", "", q, flags=re.IGNORECASE)
    q = re.sub(r"\n+\s*Для каждой точки [^.]*?производной\.?\s*$", "", q, flags=re.IGNORECASE)

    # ── 5. OCR-артефакты формул ──────────────────────────────────────────────
    q = re.sub(
        r"На\s*\n*рисунках\s*\n*изображены\s*\n*графики\s*\n*функций\s*\n*вида\s*\n*=\s*\n*y\s*\n*kx\+b\s*\.?",
        "На рисунках изображены графики функций вида y = kx + b.",
        q, flags=re.IGNORECASE,
    )
    q = re.sub(
        r"На\s*\n*рисунках\s*\n*изображены\s*\n*графики\s*\n*функций\s*\n*вида\s*\n*2\s*\n*=\s*\n*y\s*\n*ax\s*\+bx\+c\s*\.?",
        "На рисунках изображены графики функций вида y = ax² + bx + c.",
        q, flags=re.IGNORECASE,
    )
    q = re.sub(
        r"На\s+рисунке\s+изображ[её]н\s+график\s+функции\s*\n*=?\s*\n*\(?\s*\)?\s*\n*y\s*\n*f\s*x\s*\.?",
        "На рисунке изображён график функции y = f(x).",
        q, flags=re.IGNORECASE,
    )
    q = re.sub(r"вида\s*\n?\s*=\s*\n?\s*y\s*\n?\s*kx\+b\s*\.?", "вида y = kx + b.", q, flags=re.IGNORECASE)
    q = re.sub(r"в точке\s*\n*=\s*1\s*\n*x\s*\.?", "в точке x = 1.", q, flags=re.IGNORECASE)
    q = re.sub(r"в точке\s*\n*=1\s*\n*x\s*\.?", "в точке x = 1.", q, flags=re.IGNORECASE)
    q = re.sub(r"отрезке −\s*\n?\[\s*1;\s*1\]", "отрезке [−1; 1]", q)
    q = re.sub(r"отрезке\s*\n?\[\s*−1;\s*1\]", "отрезке [−1; 1]", q)
    # Убираем OCR-мусор перед формулой y = f(x)
    q = re.sub(r"=\s*\n?\s*\(\s*\)\s*\n?\s*y\s*\n?\s*f\s*x\s*\.?", "y = f(x).", q, flags=re.IGNORECASE)

    # ── 6. Нормализация строк ────────────────────────────────────────────────
    lines = [line.strip() for line in q.splitlines()]
    lines = [line for line in lines if line]
    q = "\n".join(lines)

    # ── 7. Объединяем составные заголовки ────────────────────────────────────
    q = re.sub(r"ИНТЕРВАЛЫ\s*\n\s*ВРЕМЕНИ",       "ИНТЕРВАЛЫ ВРЕМЕНИ",      q, flags=re.IGNORECASE)
    q = re.sub(r"ПЕРИОДЫ\s*\n\s*ВРЕМЕНИ",          "ПЕРИОДЫ ВРЕМЕНИ",        q, flags=re.IGNORECASE)
    q = re.sub(r"ЗНАЧЕНИЯ\s*\n\s*ПРОИЗВОДНОЙ",     "ЗНАЧЕНИЯ ПРОИЗВОДНОЙ",   q, flags=re.IGNORECASE)
    q = re.sub(r"УГЛОВЫЕ\s*\n\s*КОЭФФИЦИЕНТЫ",    "УГЛОВЫЕ КОЭФФИЦИЕНТЫ",   q, flags=re.IGNORECASE)
    q = re.sub(r"ГРАФИКИ\s*\n\s*ФУНКЦИЙ",          "ГРАФИКИ ФУНКЦИЙ",        q, flags=re.IGNORECASE)
    q = re.sub(r"ГРАФИКИ\s*\n\s*ПРОИЗВОДНЫХ",      "ГРАФИКИ ПРОИЗВОДНЫХ",    q, flags=re.IGNORECASE)

    # ── 8. Специальная обработка финансовых таблиц (58–62) ──────────────────
    if task_id in FINANCE_TASKS:
        tbl = FINANCE_TASKS[task_id]
        ascii_tbl = _ascii_table(tbl["headers"], tbl["rows"])

        # ── Intro ────────────────────────────────────────────────────────────
        intro_parts = []
        m_intro = re.search(r"В таблице показаны[^.]+\.", q, flags=re.IGNORECASE)
        if m_intro:
            intro_parts.append(m_intro.group(0).strip())
        m_pol = re.search(r"Пользуясь таблицей[^.]+\.", q, flags=re.IGNORECASE)
        if m_pol:
            intro_parts.append(m_pol.group(0).strip())
        intro = "\n".join(intro_parts) or "Пользуясь таблицей, поставьте в соответствие."

        # ── Прямой парсинг маркеров А)/1) с захватом многострочного текста ──
        # Собираем все маркеры и их позиции.
        all_markers = list(re.finditer(r"(?m)^([АБВГ1-4])\)\s*(.*)", q))

        letters: dict[str, str] = {}
        nums: dict[str, str] = {}

        for i, m in enumerate(all_markers):
            key = m.group(1)
            first_line = m.group(2).strip()
            # Захватываем текст до следующего маркера (для многострочных)
            seg_end = all_markers[i + 1].start() if i + 1 < len(all_markers) else len(q)
            tail = q[m.end(): seg_end]
            # Из хвоста берём только строки, не являющиеся заголовками/ответами
            extra = []
            for ln in tail.splitlines():
                ln = ln.strip()
                if not ln:
                    continue
                if re.fullmatch(r"[А-ЯЁA-Z\s]+", ln):  # заголовок капсом
                    break
                if re.match(r"Ответ|В таблице", ln, flags=re.IGNORECASE):
                    break
                extra.append(ln)
            full_val = re.sub(r"\s{2,}", " ",
                              (first_line + " " + " ".join(extra)).strip())
            if key in "АБВГ":
                letters[key] = full_val
            elif key in "1234":
                nums[key] = full_val

        # Собираем итоговый текст
        parts = [intro, "", ascii_tbl, "", "МЕСЯЦЫ"]
        for k in ["А", "Б", "В", "Г"]:
            parts.append(f"{k}) {letters.get(k, '—')}")
        parts += ["", "ХАРАКТЕРИСТИКИ"]
        for k in ["1", "2", "3", "4"]:
            parts.append(f"{k}) {nums.get(k, '—')}")
        parts += ["", "Ответ:\nА Б В Г", "", "В таблице под каждой буквой укажите соответствующий номер."]
        return "\n".join(parts)

    # ── 9. Специальная обработка заданий A B C D (107–128) ──────────────────
    if task_id in ABCD_TASK_IDS:
        # Извлекаем вводное предложение
        # (до появления ТОЧКИ / ЗНАЧЕНИЯ ПРОИЗВОДНОЙ / строк «A», «B», «C», «D»)
        split_points = re.search(
            r"\n(?:ТОЧКИ|ЗНАЧЕНИЯ ПРОИЗВОДНОЙ|(?:^[ABCD]\s*$))",
            q, flags=re.MULTILINE | re.IGNORECASE,
        )
        if split_points:
            intro = q[: split_points.start()].strip()
            body  = q[split_points.start():].strip()
        else:
            intro = q.strip()
            body = ""

        # Убираем заголовок «ТОЧКИ»
        body = re.sub(r"^ТОЧКИ\s*\n?", "", body, flags=re.IGNORECASE)
        # Убираем заголовок «ЗНАЧЕНИЯ ПРОИЗВОДНОЙ» (он дублирует колонку)
        body = re.sub(r"ЗНАЧЕНИЯ ПРОИЗВОДНОЙ\s*\n?", "", body, flags=re.IGNORECASE)

        # Парсим номера и значения: «1)  0,5», «2)  –0,7» и т.д.
        nums: dict[str, str] = {}
        for m in re.finditer(r"(?m)^([1-4])\)\s*(.*)", body):
            val = m.group(2).strip()
            # Убираем OCR-мусор: одиночные буквы A/B/C/D в значении
            val = re.sub(r"(?<!\w)[ABCD](?!\w)", "", val).strip()
            # Дроби, разбитые переносом: «2\n3» → «2/3»
            val = re.sub(r"(\d)\n(\d)", r"\1/\2", val)
            val = re.sub(r"\s+", " ", val).strip()
            nums[m.group(1)] = val

        # Если значения производной не распарсились — берём сырой блок
        if not nums:
            nums = {"1": "—", "2": "—", "3": "—", "4": "—"}

        return _format_derivative_task_for_vk(intro, nums)

    # ── 10. Задания 63–106: графики, только картинка + условие ─────────────
    if task_id in GRAPH_ONLY_TASK_IDS and task_id not in range(107, 129):
        # Для заданий 63–106 (угловые коэф., знаки, параболы и т.д.)
        # и 129–138 (соответствие графиков производным) — оставляем
        # только вводное предложение, таблица на картинке.

        # Исправляем знаки коэффициентов k, b до того, как обрезаем
        q = _fix_coeff_signs(q)

        # Обрезаем всё начиная с заголовка-столбца (на отдельной строке)
        # Используем \n вместо \s+, чтобы не резать «графики» внутри предложения
        q = re.split(
            r"\n(?:ГРАФИКИ(?:\s+(?:ФУНКЦИЙ|ПРОИЗВОДНЫХ))?|"
            r"КОЭФФИЦИЕНТЫ|УГЛОВЫЕ\s+КОЭФФИЦИЕНТЫ|"
            r"ФУНКЦИИ|ИНТЕРВАЛЫ|ПЕРИОДЫ|ТОЧКИ|ХАРАКТЕРИСТИКИ)\b",
            q, maxsplit=1, flags=re.IGNORECASE,
        )[0].strip()

        return q

    # ── 11. Задания 1–57: оставляем только вводное условие ─────────────────
    # Таблицы ИНТЕРВАЛЫ/ХАРАКТЕРИСТИКИ видны на изображении — убираем из текста.
    # Обрезаем всё начиная с «Пользуясь» или с заголовка таблицы.
    q = re.split(
        r"\n(?:Пользуясь|ИНТЕРВАЛЫ(?:\s+ВРЕМЕНИ)?|ПЕРИОДЫ(?:\s+ВРЕМЕНИ)?|"
        r"МЕСЯЦЫ|ХАРАКТЕРИСТИКИ|ФУНКЦИИ|ГРАФИКИ|ТОЧКИ|КОЭФФИЦИЕНТЫ)\b",
        q, maxsplit=1, flags=re.IGNORECASE,
    )[0].strip()

    q = re.sub(r"[ \t]{2,}", " ", q)
    q = re.sub(r"\n{3,}", "\n\n", q).strip()
    return q


def add(task_id: int, q: str) -> None:
    answer = ANSWER_KEY[task_id]
    q = clean_question_text(q, task_id)
    TASKS.append((q.strip(), answer, img(task_id), TOPIC))


