add(91, 'Установите соответствие между функциями и характеристиками этих функций.\nФУНКЦИИ\nХАРАКТЕРИСТИКИ\nА) y = 7 − x\n1) функция имеет точку максимума\nБ) y = 6x − x²\n2) функция имеет точку минимума\nВ) y = 12x + 2\n3) функция возрастающая\nГ) y = x² − 4x + 2\n4) функция убывающая\n\nОтвет: А Б В Г\nВ таблице под каждой буквой укажите соответствующий номер.')

add(92, 'Установите соответствие между функциями и характеристиками этих функций.\nФУНКЦИИ\nХАРАКТЕРИСТИКИ\nА) y = 2x − 3\n1) функция возрастающая\nБ) y = x² − x + 2\n2) функция убывающая\nВ) y = 4x − x²\n3) функция имеет точку минимума\nГ) y = 5 − 3x\n4) функция имеет точку максимума\n\nОтвет: А Б В Г\nВ таблице под каждой буквой укажите соответствующий номер.')

add(93, 'Установите соответствие между функциями и характеристиками этих функций.\nФУНКЦИИ\nХАРАКТЕРИСТИКИ\nА) y = 5x − x²\n1) функция убывающая\nБ) y = 2x + 1\n2) функция имеет точку максимума\nВ) y = 16 − 2x\n3) функция имеет точку минимума\nГ) y = x² − 8x + 3\n4) функция возрастающая\n\nОтвет: А Б В Г\nВ таблице под каждой буквой укажите соответствующий номер.')

add(94, 'Установите соответствие между функциями и характеристиками этих функций на отрезке [0; 6].\nФУНКЦИИ\nХАРАКТЕРИСТИКИ\nА) y = 2x − 9\n1) функция принимает положительное значение в каждой точке отрезка [0; 6]\nБ) y = x² − 3x + 5\n2) функция убывает на отрезке [0; 6]\nВ) y = −4x² + x − 1\n3) функция принимает отрицательное значение в каждой точке отрезка [0; 6]\nГ) y = −2x + 2\n4) функция возрастает на отрезке [0; 6]\n\nОтвет: А Б В Г\nВ таблице под каждой буквой укажите соответствующий номер.')

add(95, 'Установите соответствие между функциями и характеристиками этих функций на отрезке [2; 7].\nФУНКЦИИ\nХАРАКТЕРИСТИКИ\nА) y = 15 − 7x\n1) функция возрастает на отрезке [2; 7]\nБ) y = −x² + 6x − 10\n2) функция убывает на отрезке [2; 7]\nВ) y = x² − 5x + 7\n3) функция принимает отрицательное значение в каждой точке отрезка [2; 7]\nГ) y = 12x − 25\n4) функция принимает положительное значение в каждой точке отрезка [2; 7]\n\nОтвет: А Б В Г\nВ таблице под каждой буквой укажите соответствующий номер.')

add(96, 'Установите соответствие между функциями и характеристиками этих функций на отрезке [1; 5].\nФУНКЦИИ\nХАРАКТЕРИСТИКИ\nА) y = 4x − 6\n1) функция убывает на отрезке [1; 5]\nБ) y = −3x + 6\n2) функция принимает отрицательное значение в каждой точке отрезка [1; 5]\nВ) y = 2x² − 7x + 7\n3) функция принимает положительное значение в каждой точке отрезка [1; 5]\nГ) y = −x² + 4x − 5\n4) функция возрастает на отрезке [1; 5]\n\nОтвет: А Б В Г\nВ таблице под каждой буквой укажите соответствующий номер.')

add(97, 'На рисунках изображены графики функций и касательные, проведённые к ним в точках с абсциссой x₀. Установите соответствие между графиками функций и значениями производной этих функций в точке x₀.\nГРАФИКИ\nЗНАЧЕНИЯ ПРОИЗВОДНОЙ\nА)\n\nВ)\n\n1) −1/3\n2) –1,25\nБ)\n\nГ)\n\n3) 0,6\n4) 3\n\nОтвет: А Б В Г\nВ таблице под каждой буквой укажите соответствующий номер.')

add(98, 'На рисунках изображены графики функций и касательные, проведённые к ним в точках с абсциссой x₀. Установите соответствие между графиками функций и значениями производной этих функций в точке x₀.\nГРАФИКИ\nЗНАЧЕНИЯ ПРОИЗВОДНОЙ\nА)\n\nВ)\n\n1) –0,2\n2) –2,5\nБ)\n\nГ)\n\n3) 1,5\n4) 0,25\n\nОтвет: А Б В Г\nВ таблице под каждой буквой укажите соответствующий номер.')

add(99, 'На рисунках изображены графики функций и касательные, проведённые к ним в точках с абсциссой x₀. Установите соответствие между графиками функций и значениями производной этих функций в точке x₀.\nГРАФИКИ\nЗНАЧЕНИЯ ПРОИЗВОДНОЙ\nА)\n\nВ)\n\n1) 2,5\n2) –1\nБ)\n\nГ)\n\n3) −2/3\n4) 1/3\n\nОтвет: А Б В Г\nВ таблице под каждой буквой укажите соответствующий номер.')

add(100, 'На рисунках изображены графики функций и касательные, проведённые к ним в точках с абсциссой x₀. Установите соответствие между графиками функций и значениями производной этих функций в точке x₀.\nГРАФИКИ\nЗНАЧЕНИЯ ПРОИЗВОДНОЙ\nА)\n\nВ)\n\n1) –1\n2) –1,5\nБ)\n\nГ)\n\n3) 0,5\n4) 4/3\n\nОтвет: А Б В Г\nВ таблице под каждой буквой укажите соответствующий номер.')

add(101, 'На рисунках изображены графики функций и касательные, проведённые к ним в точках с абсциссой x₀. Установите соответствие между графиками функций и значениями производной этих функций в точке x₀.\nГРАФИКИ\nЗНАЧЕНИЯ ПРОИЗВОДНОЙ\nА)\n\nВ)\n\n1) −5/3\n2) 0,75\nБ)\n\nГ)\n\n3) 1\n4) –0,5\n\nОтвет: А Б В Г\nВ таблице под каждой буквой укажите соответствующий номер.')

add(102, 'На рисунках изображены графики функций вида y = kx + b. Установите соответствие между графиками функций и значениями их производной в точке x = 1.\nГРАФИКИ\nЗНАЧЕНИЯ ПРОИЗВОДНОЙ\nА)\n\nВ)\n\n1) –0,25\n2) –2\nБ)\n\nГ)\n\n3) 2/3\n4) 4\n\nОтвет: А Б В Г\nВ таблице под каждой буквой укажите соответствующий номер.')

add(103, 'На рисунках изображены графики функций вида y = kx + b. Установите соответствие между графиками функций и значениями их производной в точке x = 1.\nГРАФИКИ\nЗНАЧЕНИЯ ПРОИЗВОДНОЙ\nА)\n\nВ)\n\n1) −5/3\n2) 0,4\nБ)\n\nГ)\n\n3) 1,5\n4) −1/3\n\nОтвет: А Б В Г\nВ таблице под каждой буквой укажите соответствующий номер.')

add(104, 'На рисунках изображены графики функций вида y = kx + b. Установите соответствие между графиками функций и значениями их производной в точке x = 1.\nГРАФИКИ\nЗНАЧЕНИЯ ПРОИЗВОДНОЙ\nА)\n\nВ)\n\n1) –5\n2) 3\nБ)\n\nГ)\n\n3) –0,2\n4) 0,75\n\nОтвет: А Б В Г\nВ таблице под каждой буквой укажите соответствующий номер.')

add(105, 'На рисунках изображены графики функций вида y = kx + b. Установите соответствие между графиками функций и значениями их производной в точке x = 1.\nГРАФИКИ\nЗНАЧЕНИЯ ПРОИЗВОДНОЙ\nА)\n\nВ)\n\n1) 0,2\n2) −4/3\nБ)\n\nГ)\n\n3) –0,8\n4) 5\n\nОтвет: А Б В Г\nВ таблице под каждой буквой укажите соответствующий номер.')

add(106, 'На рисунках изображены графики функций вида y = kx + b. Установите соответствие между графиками функций и значениями их производной в точке x = 1.\nГРАФИКИ\nЗНАЧЕНИЯ ПРОИЗВОДНОЙ\nА)\n\nВ)\n\n1) 0,25\n2) 2,5\nБ)\n\nГ)\n\n3) –0,5\n4) –4\n\nОтвет: А Б В Г\nВ таблице под каждой буквой укажите соответствующий номер.')

# ── Задания 107–128: точки A B C D ──────────────────────────────────────────

add(107, 'На рисунке изображён график функции y = f(x) и отмечены точки A, B, C и D на оси Ox. Пользуясь графиком, поставьте в соответствие каждой точке характеристики функции и её производной.\nТОЧКИ\nХАРАКТЕРИСТИКИ\nA\n1) значение функции в точке положительно, а значение производной функции в точке отрицательно\nB\n2) значение функции в точке отрицательно и значение производной функции в точке отрицательно\nC\n3) значение функции в точке отрицательно, а значение производной функции в точке положительно\nD\n4) значение функции в точке положительно и значение производной функции в точке положительно\n\nОтвет: A B C D\nВ таблице под каждой буквой укажите соответствующий номер.')

add(108, 'На рисунке изображён график функции y = f(x) и отмечены точки A, B, C и D на оси Ox. Пользуясь графиком, поставьте в соответствие каждой точке характеристики функции и её производной.\nТОЧКИ\nХАРАКТЕРИСТИКИ\nA\n1) значение функции в точке положительно, а значение производной функции в точке отрицательно\nB\n2) значение функции в точке отрицательно, а значение производной функции в точке положительно\nC\n3) значение функции в точке отрицательно и значение производной функции в точке отрицательно\nD\n4) значение функции в точке положительно и значение производной функции в точке положительно\n\nОтвет: A B C D\nВ таблице под каждой буквой укажите соответствующий номер.')

add(109, 'На рисунке изображён график функции y = f(x) и отмечены точки A, B, C и D на оси Ox. Пользуясь графиком, поставьте в соответствие каждой точке характеристики функции и её производной.\nТОЧКИ\nХАРАКТЕРИСТИКИ\nA\n1) значение функции в точке отрицательно и значение производной функции в точке отрицательно\nB\n2) значение функции в точке положительно и значение производной функции в точке положительно\nC\n3) значение функции в точке отрицательно, а значение производной функции в точке положительно\nD\n4) значение функции в точке положительно, а значение производной функции в точке отрицательно\n\nОтвет: A B C D\nВ таблице под каждой буквой укажите соответствующий номер.')

add(110, 'На рисунке изображён график функции y = f(x) и отмечены точки A, B, C и D на оси Ox. Пользуясь графиком, поставьте в соответствие каждой точке характеристики функции и её производной.\nТОЧКИ\nХАРАКТЕРИСТИКИ\nA\n1) значение функции в точке положительно и значение производной функции в точке положительно\nB\n2) значение функции в точке отрицательно и значение производной функции в точке отрицательно\nC\n3) значение функции в точке положительно, а значение производной функции в точке отрицательно\nD\n4) значение функции в точке отрицательно, а значение производной функции в точке положительно\n\nОтвет: A B C D\nВ таблице под каждой буквой укажите соответствующий номер.')

add(111, 'На рисунке изображён график функции y = f(x) и отмечены точки A, B, C и D на оси Ox. Пользуясь графиком, поставьте в соответствие каждой точке характеристики функции и её производной.\nТОЧКИ\nХАРАКТЕРИСТИКИ\nA\n1) значение функции в точке отрицательно, а значение производной функции в точке положительно\nB\n2) значение функции в точке положительно, а значение производной функции в точке отрицательно\nC\n3) значение функции в точке отрицательно и значение производной функции в точке отрицательно\nD\n4) значение функции в точке положительно и значение производной функции в точке положительно\n\nОтвет: A B C D\nВ таблице под каждой буквой укажите соответствующий номер.')

add(112, 'На рисунке изображён график функции y = f(x) и отмечены точки A, B, C и D на оси Ox. Пользуясь графиком, поставьте в соответствие каждой точке характеристики функции и её производной.\nТОЧКИ\nХАРАКТЕРИСТИКИ\nA\n1) значение функции в точке положительно, а значение производной функции в точке отрицательно\nB\n2) значение функции в точке отрицательно, а значение производной функции в точке положительно\nC\n3) значение функции в точке положительно и значение производной функции в точке положительно\nD\n4) значение функции в точке отрицательно и значение производной функции в точке отрицательно\n\nОтвет: A B C D\nВ таблице под каждой буквой укажите соответствующий номер.')

add(113, 'На рисунке изображён график функции y = f(x). Числа a, b, c, d и e задают на оси Ox интервалы. Пользуясь графиком, поставьте в соответствие каждому интервалу характеристику функции или её производной.\nИНТЕРВАЛЫ\nХАРАКТЕРИСТИКИ\nА) (a; b)\n1) значение производной функции положительно в каждой точке интервала\nБ) (b; c)\n2) значение производной функции отрицательно в каждой точке интервала\nВ) (c; d)\n3) значение функции отрицательно в каждой точке интервала\nГ) (d; e)\n4) значение функции положительно в каждой точке интервала\n\nОтвет: А Б В Г\nВ таблице под каждой буквой укажите соответствующий номер.')

add(114, 'На рисунке изображён график функции y = f(x). Числа a, b, c, d и e задают на оси Ox интервалы. Пользуясь графиком, поставьте в соответствие каждому интервалу характеристику функции или её производной.\nИНТЕРВАЛЫ\nХАРАКТЕРИСТИКИ\nА) (a; b)\n1) значение производной функции отрицательно в каждой точке интервала\nБ) (b; c)\n2) функция и её производная на интервале принимают как положительные, так и отрицательные значения\nВ) (c; d)\n3) значение функции положительно в каждой точке интервала, а производная функции принимает как положительные, так и отрицательные значения\nГ) (d; e)\n4) значение производной функции положительно в каждой точке интервала\n\nОтвет: А Б В Г\nВ таблице под каждой буквой укажите соответствующий номер.')

add(115, 'На рисунке изображён график функции y = f(x). Числа a, b, c, d и e задают на оси Ox интервалы. Пользуясь графиком, поставьте в соответствие каждому интервалу характеристику функции или её производной.\nИНТЕРВАЛЫ\nХАРАКТЕРИСТИКИ\nА) (a; b)\n1) значение производной функции положительно в каждой точке интервала\nБ) (b; c)\n2) значение функции отрицательно в каждой точке интервала\nВ) (c; d)\n3) значение производной функции отрицательно в каждой точке интервала\nГ) (d; e)\n4) значение функции положительно в каждой точке интервала\n\nОтвет: А Б В Г\nВ таблице под каждой буквой укажите соответствующий номер.')

add(116, 'На рисунке изображён график функции y = f(x). Числа a, b, c, d и e задают на оси Ox интервалы. Пользуясь графиком, поставьте в соответствие каждому интервалу характеристику функции или её производной.\nИНТЕРВАЛЫ\nХАРАКТЕРИСТИКИ\nА) (a; b)\n1) значение функции положительно в каждой точке интервала\nБ) (b; c)\n2) значение производной функции отрицательно в каждой точке интервала\nВ) (c; d)\n3) значение производной функции положительно в каждой точке интервала\nГ) (d; e)\n4) значение функции отрицательно в каждой точке интервала\n\nОтвет: А Б В Г\nВ таблице под каждой буквой укажите соответствующий номер.')

add(117, 'На рисунке изображён график функции y = f(x). Числа a, b, c, d и e задают на оси Ox интервалы. Пользуясь графиком, поставьте в соответствие каждому интервалу характеристику функции или её производной.\nИНТЕРВАЛЫ\nХАРАКТЕРИСТИКИ\nА) (a; b)\n1) значение функции положительно в каждой точке интервала\nБ) (b; c)\n2) значение производной функции положительно в каждой точке интервала\nВ) (c; d)\n3) значение функции отрицательно в каждой точке интервала\nГ) (d; e)\n4) значение производной функции отрицательно в каждой точке интервала\n\nОтвет: А Б В Г\nВ таблице под каждой буквой укажите соответствующий номер.')

add(118, 'На рисунке изображён график функции y = f(x). Числа a, b, c, d и e задают на оси Ox интервалы. Пользуясь графиком, поставьте в соответствие каждому интервалу характеристику функции или её производной.\nИНТЕРВАЛЫ\nХАРАКТЕРИСТИКИ\nА) (a; b)\n1) значение производной функции положительно в каждой точке интервала\nБ) (b; c)\n2) значение производной функции отрицательно в каждой точке интервала\nВ) (c; d)\n3) значение функции отрицательно в каждой точке интервала\nГ) (d; e)\n4) значение функции положительно в каждой точке интервала\n\nОтвет: А Б В Г\nВ таблице под каждой буквой укажите соответствующий номер.')

